+
+	b[0] = p2[0] - p0[0];
+	b[1] = p2[1] - p0[1];
+	b[2] = p2[2] - p0[2];
+
+  c[0] = p3[0] - p0[0];
+  c[1] = p3[1] - p0[1];
+  c[2] = p3[2] - p0[2];
+
+  double cross[3];
+
+  CrossProduct( b, c, cross );
+
+	double volume = DotProduct( a, cross );
+
+  if ( volume < 0 )
