+#include <ros/ros.h>
+
+using namespace urdf;
+
+int g_argc;
+char** g_argv;
+
+class TestParser : public testing::Test
+{
+public:
+  Model robot;
+
+protected:
+  /// constructor
+  TestParser()
+  {
+  }
+
+
+  /// Destructor
+  ~TestParser()
